9.2 Classi astratte
Una classe astratta è una classe che non può essere istanziata direttamente — esiste solo per essere estesa. Si dichiara con la parola chiave abstract.
public abstract class Personaggio {

    private String nome;
    private int vita;
    private int vitaMax;
    private int attacco;
    private int livello;

    public Personaggio(String nome, int vitaMax, int attacco, int livello) {
        this.nome = nome;
        this.vitaMax = (vitaMax &gt; 0) ? vitaMax : 100;
        this.vita = this.vitaMax;
        this.attacco = (attacco &gt; 0) ? attacco : 10;
        this.livello = (livello &gt; 0) ? livello : 1;
    }

    // Getter
    public String getNome()  { return nome; }
    public int getVita()     { return vita; }
    public int getVitaMax()  { return vitaMax; }
    public int getAttacco()  { return attacco; }
    public int getLivello()  { return livello; }

    // Setter
    public void setVita(int vita) {
        if (vita &lt; 0) vita = 0;
        if (vita &gt; vitaMax) vita = vitaMax;
        this.vita = vita;
    }

    // Metodi concreti — ereditati da tutte le sottoclassi
    public void subirDanno(int danno) {
        setVita(vita - danno);
        System.out.println(nome + " subisce " + danno +
            " danni. Vita: " + vita + "/" + vitaMax);
    }

    public boolean isMorto() { return vita == 0; }

    public void salaDiLivello() {
        livello++;
        vitaMax += 20;
        setVita(vitaMax);
        attacco += 5;
        System.out.println(nome + " sale al livello " + livello + "!");
    }

    // Metodo astratto — ogni sottoclasse DEVE implementarlo
    public abstract void attacca(Personaggio bersaglio);

    public void stampaScheda() {
        System.out.println("=== " + nome + " [" + getClass().getSimpleName() + "] ===");
        System.out.println("Livello: " + livello + " | Vita: " +
            vita + "/" + vitaMax + " | Attacco: " + attacco);
    }
}






NoteRegole delle classi astratte




Si dichiarano con abstract class
Non possono essere istanziate direttamente — new Personaggio() dà errore
Possono avere sia metodi concreti (con implementazione) sia metodi astratti (senza)
Ogni classe figlia deve implementare tutti i metodi astratti, altrimenti deve essere astratta anche lei

9.4 Le sottoclassi concrete
Ora le sottoclassi non possono più ignorare attacca() — devono implementarlo:
public class Guerriero extends Personaggio {

    private int armatura;

    public Guerriero(String nome, int vitaMax, int attacco, int livello, int armatura) {
        super(nome, vitaMax, attacco, livello);
        this.armatura = (armatura &gt;= 0) ? armatura : 0;
    }

    @Override
    public void attacca(Personaggio bersaglio) {
        int danno = getAttacco() + 10;
        System.out.println(getNome() + " colpisce con la spada!");
        bersaglio.subirDanno(danno);
    }

    @Override
    public void subirDanno(int danno) {
        int dannoRidotto = Math.max(0, danno - armatura);
        System.out.println(getNome() + " blocca " +
            (danno - dannoRidotto) + " danni con l'armatura.");
        super.subirDanno(dannoRidotto);
    }
}
public class Mago extends Personaggio {

    private int mana;
    private int manaMax;

    public Mago(String nome, int vitaMax, int attacco, int livello, int manaMax) {
        super(nome, vitaMax, attacco, livello);
        this.manaMax = manaMax;
        this.mana = manaMax;
    }

    public int getMana() { return mana; }

    @Override
    public void attacca(Personaggio bersaglio) {
        int costoMana = 25;
        if (mana &gt;= costoMana) {
            int danno = getAttacco() * 2;
            System.out.println(getNome() + " lancia Fireball!");
            bersaglio.subirDanno(danno);
            mana -= costoMana;
            System.out.println("Mana rimasto: " + mana + "/" + manaMax);
        } else {
            System.out.println(getNome() + " non ha mana! Attacco fisico.");
            bersaglio.subirDanno(getAttacco());
        }
    }
}

9.6 Dichiarare un’interfaccia
public interface Curabile {
    void cura(int quantita);
    int getVita();
    int getVitaMax();
}
public interface Salvabile {
    String toStringSalvataggio();
    void caricaDaSalvataggio(String dati);
}
Un’interfaccia può anche avere metodi default — metodi con un’implementazione di base che le classi possono sovrascrivere o usare così com’è:
public interface Curabile {
    void cura(int quantita);
    int getVita();
    int getVitaMax();

    // Metodo default — implementazione di base
    default boolean isFerito() {
        return getVita() &lt; getVitaMax();
    }
}

9.7 Implementare un’interfaccia
Una classe implementa un’interfaccia con la parola chiave implements:
public class Guerriero extends Personaggio implements Curabile, Salvabile {

    private int armatura;

    public Guerriero(String nome, int vitaMax, int attacco, int livello, int armatura) {
        super(nome, vitaMax, attacco, livello);
        this.armatura = (armatura &gt;= 0) ? armatura : 0;
    }

    @Override
    public void attacca(Personaggio bersaglio) {
        bersaglio.subirDanno(getAttacco() + 10);
    }

    // Implementazione di Curabile
    @Override
    public void cura(int quantita) {
        setVita(getVita() + quantita);
        System.out.println(getNome() + " recupera " + quantita +
            " punti vita. Vita: " + getVita() + "/" + getVitaMax());
    }

    // Implementazione di Salvabile
    @Override
    public String toStringSalvataggio() {
        return getNome() + "," + getVita() + "," +
            getVitaMax() + "," + getAttacco() + "," + getLivello();
    }

    @Override
    public void caricaDaSalvataggio(String dati) {
        String[] parti = dati.split(",");
        // parsing e ripristino dello stato...
        System.out.println("Personaggio caricato: " + parti[0]);
    }
}






ImportantUna classe può implementare più interfacce



public class Guerriero extends Personaggio implements Curabile, Salvabile {
//                     ↑ una sola classe madre    ↑ quante interfacce si vuole
Questo è il modo in cui Java simula l’ereditarietà multipla in modo sicuro.

9.9 Esempio completo
public class Main {
    public static void main(String[] args) {

        // Non posso scrivere: new Personaggio(...) → ERRORE!
        Guerriero eroe = new Guerriero("Arthas", 150, 30, 1, 10);
        Mago mago = new Mago("Gandalf", 100, 25, 3, 120);

        eroe.stampaScheda();
        mago.stampaScheda();

        System.out.println("\n--- COMBATTIMENTO ---\n");

        mago.attacca(eroe);  // Fireball
        eroe.attacca(mago);  // Colpo con spada

        System.out.println("\n--- CURA ---\n");

        // Posso usare il tipo interfaccia come variabile
        Curabile paziente = eroe;
        if (paziente.isFerito()) {
            paziente.cura(50);
        }

        System.out.println("\n--- SALVATAGGIO ---\n");

        Salvabile salvataggio = eroe;
        String dati = salvataggio.toStringSalvataggio();
        System.out.println("Dati salvati: " + dati);
    }
}
Nota come eroe può essere trattato come Guerriero, come Curabile e come Salvabile — è lo stesso oggetto visto attraverso interfacce diverse. Questo è il polimorfismo applicato alle interfacce.

10.5 Try-catch: gestire le eccezioni
Il blocco try-catch permette di intercettare un’eccezione e gestirla senza che il programma si blocchi:
try {
    // codice che potrebbe lanciare un'eccezione
} catch (TipoEccezione e) {
    // cosa fare se quell'eccezione si verifica
}
Esempio concreto — divisione sicura:
public static int dividi(int a, int b) {
    try {
        return a / b;
    } catch (ArithmeticException e) {
        System.out.println("Errore: divisione per zero!");
        return 0;
    }
}
Esempio con input utente:
import java.util.Scanner;

Scanner sc = new Scanner(System.in);
System.out.print("Inserisci un numero: ");

try {
    int n = Integer.parseInt(sc.nextLine());
    System.out.println("Hai inserito: " + n);
} catch (NumberFormatException e) {
    System.out.println("Quello non è un numero valido!");
}

10.6 Blocchi multipli catch
Puoi gestire più tipi di eccezione con più blocchi catch:
try {
    String[] nomi = {"Arthas", "Gandalf"};
    String input = sc.nextLine();
    int indice = Integer.parseInt(input);
    System.out.println("Personaggio: " + nomi[indice]);

} catch (NumberFormatException e) {
    System.out.println("Inserisci un numero intero.");
} catch (ArrayIndexOutOfBoundsException e) {
    System.out.println("Indice fuori range! Scegli tra 0 e 1.");
} catch (Exception e) {
    // cattura qualsiasi altra eccezione
    System.out.println("Errore inaspettato: " + e.getMessage());
}






ImportantOrdine dei catch



I blocchi catch vengono valutati dall’alto verso il basso — il primo che corrisponde viene eseguito. Metti sempre i tipi più specifici prima di quelli più generici. Se metti Exception per primo, cattura tutto e i blocchi successivi non vengono mai eseguiti.

10.7 Il blocco finally
Il blocco finally viene eseguito sempre — sia che l’eccezione si verifichi, sia che non si verifichi. È utile per operazioni di pulizia: chiudere file, connessioni, scanner.
Scanner sc = new Scanner(System.in);

try {
    System.out.print("Vita del personaggio: ");
    int vita = Integer.parseInt(sc.nextLine());
    System.out.println("Vita impostata: " + vita);

} catch (NumberFormatException e) {
    System.out.println("Valore non valido!");

} finally {
    sc.close();  // viene eseguito sempre, eccezione o no
    System.out.println("Scanner chiuso.");
}






NoteTry-with-resources



Da Java 7 in poi puoi usare il try-with-resources per chiudere automaticamente le risorse senza finally:
try (Scanner sc = new Scanner(System.in)) {
    int n = Integer.parseInt(sc.nextLine());
    System.out.println("Numero: " + n);
} catch (NumberFormatException e) {
    System.out.println("Non è un numero!");
}
// sc viene chiuso automaticamente

10.8 Lanciare eccezioni con throw
Non solo puoi gestire le eccezioni — puoi anche lanciarle tu stesso con throw. Questo è utile nei setter e nei costruttori quando ricevi valori non validi:
public void setVita(int vita) {
    if (vita &lt; 0) {
        throw new IllegalArgumentException("La vita non può essere negativa: " + vita);
    }
    if (vita &gt; vitaMax) {
        throw new IllegalArgumentException("La vita non può superare vitaMax: " + vita);
    }
    this.vita = vita;
}
Chi chiama questo metodo deve gestire l’eccezione (o lasciarla propagare):
try {
    eroe.setVita(-100);
} catch (IllegalArgumentException e) {
    System.out.println("Errore: " + e.getMessage());
}

10.9 Creare eccezioni personalizzate
Puoi creare le tue eccezioni estendendo Exception (checked) o RuntimeException (unchecked):
// Eccezione personalizzata per il gioco
public class PersonaggioMortoException extends RuntimeException {

    public PersonaggioMortoException(String nomePersonaggio) {
        super("Il personaggio " + nomePersonaggio + " è morto e non può agire!");
    }
}
Usarla:
public void attacca(Personaggio bersaglio) {
    if (isMorto()) {
        throw new PersonaggioMortoException(getNome());
    }
    bersaglio.subirDanno(attacco);
}
try {
    fantasma.attacca(eroe);
} catch (PersonaggioMortoException e) {
    System.out.println(e.getMessage());
}






TipQuando creare eccezioni personalizzate



Crea eccezioni personalizzate quando vuoi dare un nome significativo a un errore specifico del tuo dominio. PersonaggioMortoException è molto più chiara di un generico IllegalStateException.

10.10 Dichiarare eccezioni con throws
Se un metodo può lanciare una checked exception ma non la gestisce internamente, deve dichiararla nella firma con throws:
public void caricaDaFile(String percorso) throws IOException {
    // questo metodo può lanciare IOException
    // chi lo chiama deve gestirla
}
Chi chiama il metodo è obbligato a gestirla:
try {
    caricaDaFile("salvataggio.txt");
} catch (IOException e) {
    System.out.println("File non trovato: " + e.getMessage());
}






Notethrow vs throws




throw (senza s) — lancia effettivamente un’eccezione all’interno del codice
throws (con s) — dichiara nella firma del metodo che potrebbe lanciare quell’eccezione

10.11 Esempio completo: input robusto
Mettiamo tutto insieme con un esempio realistico — un programma che chiede la vita del personaggio e non si blocca su input errati:
import java.util.Scanner;

public class InputRobusto {

    public static int chiediInteroPositivo(Scanner sc, String messaggio) {
        while (true) {
            System.out.print(messaggio);
            try {
                int valore = Integer.parseInt(sc.nextLine().trim());
                if (valore &lt;= 0) {
                    System.out.println("Il valore deve essere positivo. Riprova.");
                    continue;
                }
                return valore;
            } catch (NumberFormatException e) {
                System.out.println("Inserisci un numero intero valido. Riprova.");
            }
        }
    }

    public static void main(String[] args) {
        try (Scanner sc = new Scanner(System.in)) {

            System.out.println("=== CREA IL TUO PERSONAGGIO ===\n");

            System.out.print("Nome: ");
            String nome = sc.nextLine().trim();

            int vitaMax  = chiediInteroPositivo(sc, "Vita massima: ");
            int attacco  = chiediInteroPositivo(sc, "Attacco: ");
            int livello  = chiediInteroPositivo(sc, "Livello: ");

            System.out.println("\nPersonaggio creato:");
            System.out.println("Nome:    " + nome);
            System.out.println("Vita:    " + vitaMax);
            System.out.println("Attacco: " + attacco);
            System.out.println("Livello: " + livello);
        }
    }
}

11.4 ArrayList: la lista dinamica
ArrayList è la collezione più usata in Java. È come un array che si ridimensiona automaticamente.
import java.util.ArrayList;
import java.util.List;

List&lt;String&gt; inventario = new ArrayList&lt;&gt;();

// Aggiungere elementi
inventario.add("Spada del Caos");
inventario.add("Scudo di Ferro");
inventario.add("Pozione di Vita");

// Dimensione
System.out.println("Oggetti: " + inventario.size()); // 3

// Accedere a un elemento per indice
String primo = inventario.get(0);  // "Spada del Caos"

// Modificare un elemento
inventario.set(1, "Scudo Leggendario");

// Rimuovere per indice
inventario.remove(2);  // rimuove "Pozione di Vita"

// Rimuovere per valore
